public static long solve(long[] nums) {
    int n = nums.length;
    long k = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] != i) {
            k |= nums[i] & i;
        }
    }
    // Check if the array is already sorted
    boolean sorted = true;
    for (int i = 0; i < n; i++) {
        if (nums[i] != i) {
            sorted = false;
            break;
        }
    }
    if (sorted) {
        return 0;
    }
    // Now, we need to verify if the computed k allows sorting the array
    // We can model this as a graph where nodes are connected if their AND is >= k
    // Then, within each connected component, we can swap elements freely
    // So, we need to check if for every i, the correct element (i) is in the same connected component as i
    // To do this, we can use Union-Find (Disjoint Set Union)
    int[] parent = new int[n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if ((nums[i] & nums[j]) >= k) {
                union(parent, i, j);
            }
        }
    }
    // Now, check if for every i, i and nums[i] are in the same set
    for (int i = 0; i < n; i++) {
        if (find(parent, i) != find(parent, (int) nums[i])) {
            // If not, we need to find the maximum possible k that satisfies the condition
            // We can try to find the maximum k by checking the bits from highest to lowest
            long maxK = 0;
            for (long bit = 30; bit >= 0; bit--) {
                long candidate = k & (~((1L << bit) - 1));
                if (candidate <= maxK) {
                    continue;
                }
                // Check if this candidate works
                boolean valid = true;
                for (int idx = 0; idx < n; idx++) {
                    parent[idx] = idx;
                }
                for (int idx1 = 0; idx1 < n; idx1++) {
                    for (int idx2 = idx1 + 1; idx2 < n; idx2++) {
                        if ((nums[idx1] & nums[idx2]) >= candidate) {
                            union(parent, idx1, idx2);
                        }
                    }
                }
                for (int idx = 0; idx < n; idx++) {
                    if (find(parent, idx) != find(parent, (int) nums[idx])) {
                        valid = false;
                        break;
                    }
                }
                if (valid) {
                    maxK = candidate;
                }
            }
            return maxK;
        }
    }
    return k;
}

private static int find(int[] parent, int i) {
    if (parent[i] != i) {
        parent[i] = find(parent, parent[i]);
    }
    return parent[i];
}

private static void union(int[] parent, int i, int j) {
    int rootI = find(parent, i);
    int rootJ = find(parent, j);
    if (rootI != rootJ) {
        parent[rootJ] = rootI;
    }
}
