    // But since the problem allows any number of swaps, we can use union-find to group elements that can be swapped
    // and then check if each element can be placed in its correct position within its group

    int[] parent = new int[n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }

    for (int i = 0; i < n; i++) {
